const BATCH = 3;

function parseMeta(raw) {
  if (!raw) return {};
  try {
    return typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch {
    return {};
  }
}

const enabled = String($env.CONTENT_PAGE_COVER_ENABLED || '').toLowerCase() === 'true';
if (!enabled) {
  return [{
    json: {
      empty: true,
      message: 'CONTENT_PAGE_COVER_ENABLED không bật — set true trên VPS',
    },
  }];
}

const apiKey = String(
  $env.GEMINI_API_KEY
  || $env.GOOGLE_GEMINI_API_KEY
  || $env.GOOGLE_AI_API_KEY
  || $env.GENERATIVE_LANGUAGE_API_KEY
  || ''
).trim();
if (!apiKey) {
  return [{
    json: {
      empty: true,
      message: 'Thiếu GEMINI_API_KEY — lấy tại https://aistudio.google.com/apikey',
    },
  }];
}

const res = $input.first().json;
const rows = Array.isArray(res.values) ? res.values : [];
if (rows.length < 2) {
  return [{ json: { empty: true, message: 'content_drafts trống' } }];
}

const headers = rows[0].map((x) => String(x ?? '').trim().toLowerCase());
const out = [];
const blockers = {
  not_ready: 0,
  has_image: 0,
  wrong_format: 0,
  no_prompt: 0,
};

const allowedStatus = new Set(['approved', 'draft']);

for (let i = 1; i < rows.length; i++) {
  const cells = rows[i];
  if (!cells?.some((c) => String(c ?? '').trim())) continue;

  const row = { sheet_row: i + 1 };
  headers.forEach((key, j) => {
    if (key) row[key] = cells[j] ?? '';
  });

  const status = String(row.status || '').trim().toLowerCase();
  const meta = parseMeta(row.meta);

  if (!allowedStatus.has(status)) {
    blockers.not_ready += 1;
    continue;
  }

  const imageUrl = String(meta.publish_image_url || meta.cover_image_url || '').trim();
  if (imageUrl) {
    blockers.has_image += 1;
    continue;
  }

  const channel = String(meta.target_channel || '').trim().toLowerCase();
  const fmt = String(meta.content_format || '').trim().toLowerCase();
  const wantsCover =
    fmt === 'fb_page_post_image'
    || (channel === 'facebook_page' && fmt === 'fb_page_post_image');

  if (!wantsCover) {
    blockers.wrong_format += 1;
    continue;
  }

  const prompt = String(
    meta.publish_image_prompt
    || meta.cover_image_prompt
    || ''
  ).trim();
  const title = String(row.title || '').trim();
  const hook = String(row.hook_line || '').trim();

  if (!prompt && !title && !hook) {
    blockers.no_prompt += 1;
    continue;
  }

  if (status === 'draft' && meta.publish_image_pending !== true && !meta.needs_cover_image) {
    blockers.not_ready += 1;
    continue;
  }

  row.meta_parsed = meta;
  out.push({ json: row });
  if (out.length >= BATCH) break;
}

if (!out.length) {
  return [{
    json: {
      empty: true,
      message: 'Không có bài cần cover — cần fb_page_post_image + thiếu publish_image_url + có prompt/title',
      blockers,
    },
  }];
}

return out;

const data = $getWorkflowStaticData('global');
data.cpc_stats = { cover_ok: 0, generate_fail: 0, drive_fail: 0, other_fail: 0 };
return $input.all();

const row = $('Loop Cover Candidates').item?.json || $input.first().json;
const meta = row.meta_parsed || {};

const title = String(row.title || '').trim();
const hook = String(row.hook_line || '').trim();
const basePrompt = String(
  meta.publish_image_prompt
  || meta.cover_image_prompt
  || title
  || hook
).trim();

const headline = hook || title || 'Magnix NOXH';
const pillar = String(meta.content_pillar || 'B').trim();

const brandRules = [
  'Professional Vietnamese social media cover for Facebook Page.',
  'Style: trustworthy financial/legal advisory, clean modern layout.',
  'Colors: deep teal #0D7377 and white, subtle checklist or folder icon.',
  'NO stock photo watermarks. NO fake government logos.',
  'Readable Vietnamese headline text on image (large, high contrast).',
  'Square 1:1 composition, safe margins for mobile crop.',
  'Small subtle "Magnix" wordmark bottom-right.',
].join(' ');

const pillarHint = {
  A: 'Focus: income eligibility, salary documents.',
  B: 'Focus: application forms, checklist, folder templates.',
  C: 'Focus: community trust, Q&A helpful tone.',
}[pillar] || '';

const userPrompt = [
  basePrompt,
  pillarHint,
  `Headline text on image (Vietnamese): "${headline.slice(0, 80)}"`,
  'Avoid: guarantees, approval promises, specific interest rates.',
].filter(Boolean).join('\n');

const fullPrompt = `${brandRules}\n\n${userPrompt}`.slice(0, 4000);

const aspect = String($env.PAGE_COVER_ASPECT_RATIO || '1:1').trim();

return [{
  json: {
    ok: true,
    sheet_row: row.sheet_row,
    normalized_key: row.source_normalized_key,
    segment: row.segment,
    title,
    hook_line: hook,
    cover_prompt: fullPrompt,
    aspect_ratio: aspect,
    meta_parsed: meta,
  },
}];

const item = $input.first().json;
if (!item.ok || !item.cover_prompt) {
  return [{ json: { ...item, generate_ok: false, generate_error: 'NO_PROMPT' } }];
}

const apiKey = String(
  $env.GEMINI_API_KEY
  || $env.GOOGLE_GEMINI_API_KEY
  || $env.GOOGLE_AI_API_KEY
  || $env.GENERATIVE_LANGUAGE_API_KEY
  || ''
).trim();
const model = String(
  $env.GEMINI_IMAGE_MODEL || 'gemini-2.5-flash-image'
).trim();

if (!apiKey) {
  return [{
    json: {
      ...item,
      generate_ok: false,
      generate_error: 'MISSING_GEMINI_API_KEY',
    },
  }];
}

const url = `https://generativelanguage.googleapis.com/v1beta/models/${encodeURIComponent(model)}:generateContent?key=${encodeURIComponent(apiKey)}`;

const body = {
  contents: [{ role: 'user', parts: [{ text: item.cover_prompt }] }],
  generationConfig: {
    responseModalities: ['IMAGE'],
    imageConfig: {
      aspectRatio: item.aspect_ratio || '1:1',
    },
  },
};

try {
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url,
    headers: { 'Content-Type': 'application/json' },
    body,
    json: true,
    timeout: 120000,
  });

  const parts = res?.candidates?.[0]?.content?.parts || [];
  let inline = null;
  for (const p of parts) {
    if (p.inlineData?.data) {
      inline = p.inlineData;
      break;
    }
  }

  if (!inline?.data) {
    const block = res?.promptFeedback?.blockReason || res?.candidates?.[0]?.finishReason;
    return [{
      json: {
        ...item,
        generate_ok: false,
        generate_error: block ? `BLOCKED:${block}` : 'NO_IMAGE_IN_RESPONSE',
        gemini_model: model,
      },
    }];
  }

  const mime = String(inline.mimeType || 'image/png').trim();
  const ext = mime.includes('jpeg') ? 'jpg' : 'png';

  return [{
    json: {
      ...item,
      generate_ok: true,
      image_base64: inline.data,
      image_mime: mime,
      image_ext: ext,
      gemini_model: model,
    },
  }];
} catch (e) {
  const detail = e.response?.data || e.cause?.response?.data || e.message;
  const msg = detail?.error?.message || (typeof detail === 'string' ? detail : JSON.stringify(detail).slice(0, 400));
  return [{
    json: {
      ...item,
      generate_ok: false,
      generate_error: msg || 'GEMINI_REQUEST_FAILED',
      gemini_model: model,
    },
  }];
}

function slugify(s) {
  return String(s || 'cover')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-zA-Z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 48)
    .toLowerCase() || 'cover';
}

function buildFileName(item) {
  const key = String(item.normalized_key || '').trim();
  const slug = slugify(item.title || item.hook_line);
  const date = new Date().toISOString().slice(0, 10).replace(/-/g, '');
  const shortKey = key.includes(':') ? key.split(':').pop() : key.slice(0, 12);
  return `magnix-page-cover-${shortKey || slug}-${date}.${item.image_ext || 'png'}`;
}

const item = $input.first().json;
if (!item.generate_ok || !item.image_base64) {
  return [{ json: { ...item, drive_ok: false, drive_skip: true } }];
}

const folderId =
  $env.DRIVE_PAGE_COVERS_FOLDER_ID
  || '1EVNn-4ASRhZwSnnapBkMzbHjdIjCNhBJ';

if (!folderId || String(folderId).startsWith('__')) {
  return [{
    json: {
      ...item,
      drive_ok: false,
      drive_error: 'MISSING_DRIVE_PAGE_COVERS_FOLDER_ID',
      hint: 'Chạy: node scripts/init-magnix-drive-page-covers.mjs',
    },
  }];
}

const fileName = buildFileName(item);
const buf = Buffer.from(item.image_base64, 'base64');
if (!buf.length) {
  return [{ json: { ...item, drive_ok: false, drive_error: 'EMPTY_IMAGE_BUFFER' } }];
}

const mime = item.image_mime || 'image/png';
const boundary = `magnix_cover_${Date.now()}`;
const metadata = JSON.stringify({
  name: fileName,
  parents: [folderId],
  mimeType: mime,
  description: [
    'Magnix Page Cover',
    item.normalized_key || '',
    item.gemini_model || '',
  ].filter(Boolean).join(' | ').slice(0, 500),
});

const multipartBody = Buffer.concat([
  Buffer.from(`--${boundary}\r\nContent-Type: application/json; charset=UTF-8\r\n\r\n${metadata}\r\n`),
  Buffer.from(`--${boundary}\r\nContent-Type: ${mime}\r\n\r\n`),
  buf,
  Buffer.from(`\r\n--${boundary}--`),
]);

try {
  const uploaded = await this.helpers.httpRequestWithAuthentication.call(this, 'googleApi', {
    method: 'POST',
    url: 'https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart&fields=id,name,webViewLink,webContentLink,size&supportsAllDrives=true',
    headers: {
      'Content-Type': `multipart/related; boundary=${boundary}`,
    },
    body: multipartBody,
    json: true,
  });

  const fileId = uploaded.id;
  if (!fileId) {
    return [{ json: { ...item, drive_ok: false, drive_error: 'NO_FILE_ID' } }];
  }

  await this.helpers.httpRequestWithAuthentication.call(this, 'googleApi', {
    method: 'POST',
    url: `https://www.googleapis.com/drive/v3/files/${fileId}/permissions?supportsAllDrives=true`,
    headers: { 'Content-Type': 'application/json' },
    body: { role: 'reader', type: 'anyone' },
    json: true,
  });

  const publishUrl = `https://drive.google.com/uc?export=view&id=${fileId}`;

  return [{
    json: {
      ...item,
      drive_ok: true,
      drive_file_id: fileId,
      drive_file_name: uploaded.name || fileName,
      drive_view_url: uploaded.webViewLink || `https://drive.google.com/file/d/${fileId}/view`,
      publish_image_url: publishUrl,
      drive_folder_id: folderId,
      drive_size_bytes: uploaded.size ? Number(uploaded.size) : buf.length,
    },
  }];
} catch (e) {
  return [{
    json: {
      ...item,
      drive_ok: false,
      drive_error: 'DRIVE_UPLOAD_FAILED',
      drive_message: String(e.message || e),
      drive_file_name: fileName,
    },
  }];
}

const SHEET_ID = '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const DRAFTS_TAB = 'content_drafts';

const item = $input.first().json;
const row = item.sheet_row;
if (!row) {
  return [{ json: { ok: false, skip: true, reason: 'NO_SHEET_ROW' } }];
}

const loopRow = $('Loop Cover Candidates').item?.json || {};
const existingMeta = item.meta_parsed || loopRow.meta_parsed || {};

if (item.generate_ok === false || !item.drive_ok || !item.publish_image_url) {
  const errMeta = {
    ...existingMeta,
    cover_generate_error: item.generate_error || item.drive_error || item.drive_message || 'UNKNOWN',
    cover_generate_at: new Date().toISOString(),
    cover_agent: 'content-page-cover',
  };
  return [{
    json: {
      ok: false,
      sheet_row: row,
      normalized_key: item.normalized_key,
      sheet_batch_url: `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values:batchUpdate`,
      sheet_batch_body: {
        valueInputOption: 'USER_ENTERED',
        data: [
          { range: `${DRAFTS_TAB}!N${row}`, values: [[JSON.stringify(errMeta).slice(0, 50000)]] },
        ],
      },
      cover_ok: false,
    },
  }];
}

const metaPatch = {
  ...existingMeta,
  publish_image_url: item.publish_image_url,
  cover_image_url: item.publish_image_url,
  drive_cover_file_id: item.drive_file_id,
  drive_cover_file_name: item.drive_file_name,
  drive_cover_view_url: item.drive_view_url,
  cover_generated_at: new Date().toISOString(),
  cover_agent: 'content-page-cover',
  cover_gemini_model: item.gemini_model || null,
  publish_image_pending: false,
};

const metaStr = JSON.stringify(metaPatch).slice(0, 50000);

return [{
  json: {
    ok: true,
    sheet_row: row,
    normalized_key: item.normalized_key,
    publish_image_url: item.publish_image_url,
    sheet_batch_url: `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values:batchUpdate`,
    sheet_batch_body: {
      valueInputOption: 'USER_ENTERED',
      data: [
        { range: `${DRAFTS_TAB}!N${row}`, values: [[metaStr]] },
      ],
    },
    cover_ok: true,
  },
}];

const data = $getWorkflowStaticData('global');
if (!data.cpc_stats) data.cpc_stats = {};
data.cpc_stats.cover_ok = (data.cpc_stats.cover_ok || 0) + 1;
return $input.all();

const data = $getWorkflowStaticData('global');
if (!data.cpc_stats) data.cpc_stats = {};
const item = $input.first().json;
if (item.cover_ok) {
  data.cpc_stats.cover_ok = (data.cpc_stats.cover_ok || 0) + 1;
} else if (item.generate_ok === false) {
  data.cpc_stats.generate_fail = (data.cpc_stats.generate_fail || 0) + 1;
} else if (item.drive_ok === false) {
  data.cpc_stats.drive_fail = (data.cpc_stats.drive_fail || 0) + 1;
} else {
  data.cpc_stats.other_fail = (data.cpc_stats.other_fail || 0) + 1;
}
return $input.all();

const data = $getWorkflowStaticData('global');
const stats = data.cpc_stats || {};
let hint = null;
if ((stats.cover_ok || 0) === 0) {
  if (stats.no_candidates) hint = 'Không candidate — cần fb_page_post_image + thiếu publish_image_url';
  else if ((stats.generate_fail || 0) > 0) hint = 'Gemini fail — kiểm tra GEMINI_API_KEY + GEMINI_IMAGE_MODEL';
  else if ((stats.drive_fail || 0) > 0) hint = 'Drive upload fail — googleApi credential + DRIVE_PAGE_COVERS_FOLDER_ID';
  else hint = 'Bật CONTENT_PAGE_COVER_ENABLED=true + GEMINI_API_KEY';
}
return [{ json: {
  ok: true,
  workflow: 'content-page-cover',
  stats,
  batch_size: 3,
  hint,
  finished_at: new Date().toISOString(),
}}];

const data = $getWorkflowStaticData('global');
if (!data.cpc_stats) data.cpc_stats = {};
data.cpc_stats.no_candidates = true;
const msg = $input.first()?.json?.message || 'No cover candidates';
return [{ json: { ok: true, empty: true, message: msg, blockers: $input.first()?.json?.blockers } }];
